                               <span className={`text-[9px] font-bold uppercase tracking-[0.1em] px-2 py-0.5 rounded-sm ${colorMap[a.color].text} bg-white/[0.03] border border-white/[0.05]`}>
                                 {a.type}
                               </span>
                             </div>
                           </div>
                         ))}
                       </div>
                    </div>

                    {/* Risk & Retest */}
                    <div className="flex flex-col gap-6">
                      {/* Risks */}
                      <div className="relative rounded-3xl border border-white/[0.04] bg-[#0D1117]/60 backdrop-blur-2xl p-6 group transition-all duration-500 hover:border-white/[0.08] hover:-translate-y-1">
                        <h3 className={`${syne.className} text-[11px] font-bold tracking-[0.15em] text-white/50 uppercase mb-4`}>Risk Matrix</h3>
                        <div className="grid grid-cols-2 gap-3">
                          {risks.map(r => (
                            <div key={r.label} className={`p-3 rounded-xl border border-white/[0.03] bg-white/[0.02] flex flex-col gap-2 relative overflow-hidden group/risk hover:bg-white/[0.04] transition-colors`}>
                              <div className={`absolute top-0 left-0 w-1 h-full ${colorMap[r.color].bg}`} />
                              <span className="text-[10px] text-white/50 font-medium uppercase tracking-wider">{r.label}</span>
                              <span className={`text-[12px] font-bold tracking-wide ${colorMap[r.color].text}`}>{r.level}</span>
                            </div>
                          ))}
                        </div>
                      </div>

                      {/* Retest */}
                      <div className="relative rounded-3xl border border-white/[0.04] bg-[#0D1117]/60 backdrop-blur-2xl p-6 mt-auto overflow-hidden group hover:border-[#00F5C4]/20 transition-colors duration-500">
                        <div className="absolute -right-10 -bottom-10 w-40 h-40 bg-[#00F5C4]/10 blur-[50px] rounded-full pointer-events-none" />
                        <div className="flex items-center justify-between mb-4">
                           <h3 className={`${syne.className} text-[11px] font-bold tracking-[0.15em] text-white/50 uppercase`}>Next Protocol</h3>
                           <span className="text-[10px] text-[#00F5C4] font-bold bg-[#00F5C4]/10 px-2 py-1 rounded border border-[#00F5C4]/20">84 DAYS</span>
                        </div>
                        <div className="flex items-end gap-3 mb-4">
                          <span className={`text-4xl font-black ${syne.className}`}>Jun 19</span>
                        </div>
                        <button className="w-full py-3 rounded-xl bg-white/[0.03] border border-white/10 hover:bg-[#00F5C4] hover:text-black hover:border-transparent transition-all duration-300 font-bold text-xs tracking-wider uppercase flex justify-center items-center gap-2">
                          Schedule Retest <ArrowUpRight size={14} />
                        </button>
                      </div>
                    </div>

                  </div>
                </motion.div>
              </div>

              {/* Biomarkers section */}
              <motion.div variants={containerVariants} className="pt-4">
                <div className="flex items-end justify-between mb-6 px-2">
                  <h2 className={`${syne.className} text-xl tracking-[0.1em] font-bold text-white/90`}>KEY BIOMARKERS</h2>
                  <div className="h-[1px] flex-1 mx-6 bg-gradient-to-r from-white/10 to-transparent hidden sm:block" />
                  <button className="text-[10px] font-bold text-[#00F5C4] hover:text-white uppercase tracking-[0.15em] flex items-center gap-1 transition-colors">
                    View Full Matrix <ChevronRight size={12} />
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {biomarkers.map((b, i) => (
                    <motion.div variants={itemVariants} key={b.name} className="relative group cursor-pointer">
                      <div className="absolute inset-0 bg-gradient-to-br from-white/[0.05] to-transparent rounded-[24px] pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-500" />

                      <div className={`p-6 rounded-[24px] bg-[#0D1117]/80 backdrop-blur-xl border border-white/[0.04] transition-all duration-500 group-hover:border-${b.color}-400/30 group-hover:-translate-y-1.5 group-hover:shadow-[0_10px_30px_rgba(0,0,0,0.5)]`}>

                        <div className="flex justify-between items-start mb-4">
                          <div className="flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center border ${colorMap[b.color].bg} ${colorMap[b.color].border} group-hover:${colorMap[b.color].glow} transition-all duration-500`}>
                              <b.icon size={16} className={colorMap[b.color].text} />
                            </div>
                            <div>
                               <h4 className="text-[13px] font-bold text-white/80">{b.name}</h4>
                               <span className={`text-[9px] font-black uppercase tracking-[0.15em] ${colorMap[b.color].text}`}>{b.status}</span>
                            </div>
                          </div>
                          <div className={`text-right ${syne.className}`}>
                            <div className="flex items-baseline gap-1 justify-end">
                              <span className="text-2xl font-bold text-white tracking-tighter">
                                <AnimatedNumber value={b.value} decimals={b.decimals} />
                              </span>
                              <span className="text-[10px] text-white/40 tracking-widest">{b.unit}</span>
                            </div>
                          </div>
                        </div>

                        <Spark data={b.spark} colorHex={colorMap[b.color].hex} />

                        <div className="flex justify-between items-center mt-5 pt-4 border-t border-white/[0.04]">
                          <div className="flex items-center gap-1.5">
                            {b.trend === 'down' && <TrendingDown size={14} className={colorMap[b.color].text} />}
                            {b.trend === 'up' && <TrendingUp size={14} className={colorMap[b.color].text} />}
                            {b.trend === 'stable' && <Minus size={14} className="text-white/40" />}
                            <span className="text-[11px] font-medium text-white/50">{b.change}</span>
                          </div>
                          <span className="text-[10px] tracking-wider text-white/30 uppercase">Ref: {b.range}</span>
                        </div>
                      </div>
                    </motion.div>
                  ))}
                </div>
              </motion.div>

              <div className="h-12" /> {/* Bottom padding */}
            </motion.div>
          </div>
        </main>
      </div>
    </div>
  );
}
